def compute_score() -> tuple[str, float]:
    # Check ppt_diff for added/removed/modified slides that are not slide 8
    changed_slides = set()
    for s in ppt_diff.added_slides + ppt_diff.removed_slides:
        changed_slides.add(s.slide_number)
    for orig, mod in ppt_diff.modified_slides:
        changed_slides.add(orig.slide_number)
    for orig, mod in ppt_diff.added_animations + ppt_diff.removed_animations:
        changed_slides.add(orig.slide_number)
    for orig, mod in ppt_diff.modified_animations:
        changed_slides.add(orig.slide_number)
    for orig, mod in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        changed_slides.add(orig.slide_number)
    for orig, mod in ppt_diff.modified_transitions:
        changed_slides.add(orig.slide_number)
    extraneous = [s for s in changed_slides if s != 8]
    if extraneous:
        return f"Extraneous changes made to slides: {extraneous}", 0.0
    return "No extraneous changes to slides other than slide 8.", 1.0

def compute_score() -> tuple[str, float]:
    # Check ppt_diff for animation/transition changes on slide 8
    changes = []
    for anim in ppt_diff.added_animations:
        if anim.slide_id == '8' or anim.slide_id == 8:
            changes.append('added animation')
    for anim in ppt_diff.removed_animations:
        if anim.slide_id == '8' or anim.slide_id == 8:
            changes.append('removed animation')
    for orig, mod in ppt_diff.modified_animations:
        if orig.slide_id == '8' or orig.slide_id == 8:
            changes.append('modified animation')
    for trans in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        if trans.slide_id == '8' or trans.slide_id == 8:
            changes.append('transition change')
    for orig, mod in ppt_diff.modified_transitions:
        if orig.slide_id == '8' or orig.slide_id == 8:
            changes.append('modified transition')
    if changes:
        return f"Unintended animation/transition changes to slide 8: {changes}", 0.0
    return "No unintended animation/transition changes to slide 8.", 1.0
